import{_ as a,C as l,o as n,c as s,j as o,E as r,a as i,a3 as m}from"./chunks/framework.DACwFHq9.js";const T=JSON.parse('{"title":"话题命名","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/settings/topic-naming.md","filePath":"user-guide/tools/llm-chat/settings/topic-naming.md","lastUpdated":1778239080000}'),d={name:"user-guide/tools/llm-chat/settings/topic-naming.md"},g={id:"话题命名",tabindex:"-1"};function c(u,t,p,h,_,P){const e=l("LIcon");return n(),s("div",null,[o("h1",g,[r(e,{name:"PenTool",size:"28"}),t[0]||(t[0]=i(" 话题命名 ",-1)),t[1]||(t[1]=o("a",{class:"header-anchor",href:"#话题命名","aria-label":'Permalink to "<LIcon name="PenTool" size="28" /> 话题命名"'},"​",-1))]),t[2]||(t[2]=m('<p>话题命名模块负责将会话从枯燥的“新会话”自动转换为具有描述性的标题，方便你在侧边栏快速定位历史记录。</p><h2 id="自动化策略-automation" tabindex="-1">自动化策略 (Automation) <a class="header-anchor" href="#自动化策略-automation" aria-label="Permalink to &quot;自动化策略 (Automation)&quot;">​</a></h2><ul><li><strong>启用话题命名</strong>: 总开关。开启后，系统将监控对话进度。</li><li><strong>自动触发阈值</strong>: <ul><li><strong>说明</strong>: 设置在用户发送多少条消息后触发自动命名。</li><li><strong>建议</strong>: 设为 2-3 条。此时对话主题通常已经明确，生成的标题最为准确。</li></ul></li><li><strong>上下文引用数</strong>: <ul><li><strong>说明</strong>: 生成标题时参考的最近消息条数。</li><li><strong>作用</strong>: 确保模型能捕捉到最新的讨论核心。</li></ul></li></ul><h2 id="模型与指令-model-prompt" tabindex="-1">模型与指令 (Model &amp; Prompt) <a class="header-anchor" href="#模型与指令-model-prompt" aria-label="Permalink to &quot;模型与指令 (Model &amp; Prompt)&quot;">​</a></h2><ul><li><strong>命名模型</strong>: <ul><li><strong>建议</strong>: 使用轻量级模型（如 GPT-4o-mini 或本地小型模型）。命名任务对逻辑要求不高，小模型速度更快且成本更低。</li></ul></li><li><strong>命名提示词 (Prompt Editor)</strong>: <ul><li><strong>高度灵活</strong>: 你可以要求模型生成特定风格的标题（如：极其简短、包含 Emoji、学术风格）。</li><li><strong>占位符</strong>: 使用 <code>{context}</code> 标记对话内容注入的位置。如果未提供，内容将自动追加到提示词末尾。</li></ul></li></ul><h2 id="生成控制" tabindex="-1">生成控制 <a class="header-anchor" href="#生成控制" aria-label="Permalink to &quot;生成控制&quot;">​</a></h2><ul><li><strong>温度 (Temperature)</strong>: 建议设为 0.1 - 0.3。较低的随机性有助于生成更直白、不花哨的标题。</li><li><strong>输出上限 (Max Tokens)</strong>: 建议限制在 20-50 tokens 以内，防止模型生成一段话作为标题。</li></ul><hr><div class="tip custom-block"><p class="custom-block-title">提示</p><p><strong>手动干预</strong>: 即使自动生成了标题，你随时可以双击侧边栏的会话项或在会话设置中手动修改标题。手动修改后的标题不会被自动命名再次覆盖。</p></div>',9))])}const b=a(d,[["render",c]]);export{T as __pageData,b as default};
